class FileSize:
    def __init__(self, bytes):
        self._bytes = bytes

    @property
    def bytes(self):
        return self._bytes

    @bytes.setter
    def bytes(self, value):
        if not isinstance(value, int) or value < 0:
            raise ValueError("Bytes must be a non-negative integer")
        self._bytes = value

    @property
    def kilobytes(self):
        return self._bytes / 1024

    @property
    def megabytes(self):
        return self._bytes / (1024 * 1024)

    @property
    def gigabytes(self):
        return self._bytes / (1024 * 1024 * 1024)


if __name__ == "__main__":
    bytes_input = int(input())
    file = FileSize(bytes_input)
    print(f"{file.kilobytes:.2f}")
    print(f"{file.megabytes:.2f}")
    print(f"{file.gigabytes:.2f}")
